  ('social-worker-moex-01921', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '田野研究基於不同的理論典範而有不同的研究設計，認為社會真實是社會建構出來的，社會真實的描述 除了被研究者所陳述的故事訊息外，還需要了解其故事背後的社會意義。是屬於下列何理論典範？', '["俗民方法論", "紮根理論", "建制民族誌", "自然主義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01922', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一種研究設計的重點是讓被研究者在參與研究的過程中，有機會為解決自身群體的問題或創造群體的自 身利益，而採取一連串的行動。是指何種研究方法？', '["個案研究方法", "行動研究", "參與觀察研究", "單案研究法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01923', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為了有效評估日益嚴重的離婚問題，研究者研究目標是要形成造成離婚的基礎理論，研究是否離婚者的 人格、婚姻模式、問題解決模式具有基本上的特質，這種以形成理論為基礎的研究，是指下列何者？', '["基礎性研究評估", "應用性研究評估", "總結性評估", "形成性評估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01924', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '觀察者在一段特定時間內，直接觀察目標行為，而且記錄每一次發生所持續的時間長度，是直接觀察法 常用的那一種記錄方法？', '["等距記錄法", "頻率記錄法", "持續記錄法", "強度記錄法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
