  ('social-worker-moex-01930', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '黃同學參加2017年2月的全民英檢中級聽讀測驗，他的成績位在第95百分位；他於2017年8月再次參 加全民英檢中級聽讀測驗，這次他的成績位於第82百分位，請問黃同學第二次得到較低的成績最可能是 因為下列那一種內在無效度（internal invalidity）的來源？', '["測驗", "測量工具", "統計迴歸", "自暴自棄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
